import streamlit as stimport plotly.express as pxfrom backend import get_dataimport sys# Add title, text input, slider, selectbox and subheader# st.set_page_config(layout="wide")st.set_page_config(    page_title="Weather Forecast",    page_icon="📈"  # optional)st.title("Weather Forecast")st.subheader("5 Day / 3 Hour ")place = st.text_input("Place", value="Singapore")st.text("")days = st.slider("Forecast Days", min_value= 1, max_value=5, help="Select the number of forecasted days")st.text("")option = st.selectbox("Select data to view", ["Temperature", "Sky"], filter_mode=None)st.subheader(f"{option} for the next {days} days in {place}")if place:    try:        # Get the temperature / sky data        filtered_data = get_data(place, days)        if option == "Temperature":            # list comprehension to extract temperature data from the filtered data            temperatures = [dict['main']['temp'] / 10 for dict in filtered_data]            dates = [dict["dt_txt"] for dict in filtered_data]            # Create a temperature plot            figure = px.line(x=dates, y=temperatures, labels={"x": "Date", "y": "Temperature (°C)"})            st.plotly_chart(figure)        if option == "Sky":            images = {"Clear": "images/clear.png", "Clouds": "images/cloud.png", "Rain": "images/rain.png", "Snow": "images/snow.png"}            sky_conditions = [dict["weather"][0]["main"] for dict in filtered_data]            dates = [dict["dt_txt"] for dict in filtered_data]            # Translating the data: Use list comprehension to translate the sky condition data into a list of image paths            image_paths = [images[condition] for condition in sky_conditions]            print()            st.image(image_paths, width=115, caption=dates)    except KeyError:        st.write("That place doesn't exist. Please enter a valid place name.")